<?php
namespace app\Repositories;
class UserRepository extends BaseRepository{ public function findByEmail(string $email):?array{return $this->fetch("SELECT u.*,r.name role_name,r.display_name role_display FROM users u JOIN roles r ON r.id=u.role_id WHERE u.email=?",[$email]);} public function findById(int $id):?array{return $this->fetch("SELECT u.*,r.name role_name,r.display_name role_display FROM users u JOIN roles r ON r.id=u.role_id WHERE u.id=?",[$id]);} public function findByApiToken(string $token):?array{return $this->fetch("SELECT u.*,r.name role_name,r.display_name role_display FROM users u JOIN roles r ON r.id=u.role_id WHERE u.api_token=? AND u.status='active'",[$token]);} public function all():array{return $this->fetchAll("SELECT u.id,u.full_name,u.email,u.phone,u.student_code,u.class_name,u.major,u.status,u.created_at,r.name role_name,r.display_name role_display FROM users u JOIN roles r ON r.id=u.role_id ORDER BY u.id DESC");} public function roles():array{return $this->fetchAll("SELECT * FROM roles ORDER BY id");} public function create(array $d):int{$this->execute("INSERT INTO users(full_name,email,phone,student_code,class_name,major,password,role_id,status) VALUES(?,?,?,?,?,?,?,?,?)",[$d['full_name'],$d['email'],$d['phone']??null,$d['student_code']??null,$d['class_name']??null,$d['major']??null,$d['password'],$d['role_id']??2,$d['status']??'active']);return $this->lastInsertId();} public function updateProfile(int $id,array $d):bool{return $this->execute("UPDATE users SET full_name=?,phone=?,student_code=?,class_name=?,major=? WHERE id=?",[$d['full_name'],$d['phone']??null,$d['student_code']??null,$d['class_name']??null,$d['major']??null,$id]);} public function updatePassword(int $id,string $hash):bool{return $this->execute("UPDATE users SET password=? WHERE id=?",[$hash,$id]);} public function updateToken(int $id,?string $token):bool{return $this->execute("UPDATE users SET api_token=? WHERE id=?",[$token,$id]);} public function updateRoleStatus(int $id,int $roleId,string $status):bool{return $this->execute("UPDATE users SET role_id=?,status=? WHERE id=?",[$roleId,$status,$id]);} public function countAdmins():int{return (int)$this->fetch("SELECT COUNT(*) c FROM users u JOIN roles r ON r.id=u.role_id WHERE r.name='admin' AND u.status='active'")['c'];} public function delete(int $id):bool{return $this->execute("DELETE FROM users WHERE id=?",[$id]);}}
